// Pre-allocated RT-safe logging (use in all RT threads):
struct RtLogEntry {
    TimestampNs timestamp;
    char message[64];
};

LockFreeRingBuffer<RtLogEntry, 256> g_rt_log_buffer;

// In RT thread (vision, track, actuation):
void log_event(const char* msg) {
    RtLogEntry entry{get_timestamp(), {0}};
    strncpy(entry.message, msg, sizeof(entry.message) - 1);
    g_rt_log_buffer.push(entry);  // Lock-free, no allocation
}

// Async logger thread (non-RT):
void logger_thread() {
    RtLogEntry entry;
    while (running) {
        if (g_rt_log_buffer.pop(entry)) {
            // Safe to use std::cout/fprintf in non-RT thread
            printf("[%lu] %s\n", entry.timestamp, entry.message);
        }
        std::this_thread::sleep_for(std::chrono::milliseconds(10));
    }
}
